2614         break;
2615       default:
2616         break;
2617       }
2618     }
2619 
2620     // This transform works with scalable and fixed vectors
2621     // TODO: Identify and allow other scalable transforms
2622     if (isa<VectorType>(I.getType())) {
2623       MadeChange |= scalarizeBinopOrCmp(I);
2624       MadeChange |= scalarizeLoadExtract(I);
2625       MadeChange |= scalarizeVPIntrinsic(I);
2626     }
